def inclusion_exclusion(A, B, C=None):
    """Count union using inclusion-exclusion"""
    if C is None:
        # Two sets
        return len(A) + len(B) - len(A & B)
    else:
        # Three sets
        return (len(A) + len(B) + len(C)
                - len(A & B) - len(B & C) - len(A & C)
                + len(A & B & C))

# Example: Students in Math, CS, Physics
math = {1, 2, 3, 4, 5}
cs = {3, 4, 5, 6, 7}
physics = {5, 6, 7, 8}

print(f'At least one subject: {inclusion_exclusion(math, cs, physics)}')
# Output: 8
